+                self.populateRecentListMenu(
+                    menu,
+                    header: header,
+                    actions: actions,
+                    extras: staleExtras,
+                    content: .message("Timed out")
+                )
+            }
+        } catch {
+            if stale == nil {
+                self.populateRecentListMenu(
+                    menu,
+                    header: header,
+                    actions: actions,
+                    extras: staleExtras,
+                    content: .message("Failed to load")
+                )
+            }
+        }
